)

type createNetworkRequest struct {
	Name  string   `json:"name"`
	CIDRs []string `json:"cidrs"`
}

func (s *Server) handleCreateNetwork(w http.ResponseWriter, r *http.Request) {
	if !actorIsAdmin(r.Context()) {
		writeError(w, http.StatusForbidden, "network creation requires the admin role")
		return
	}
	var req createNetworkRequest
	if err := decodeJSONStrict(r, &req); err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	if req.Name == "" {
		writeError(w, http.StatusBadRequest, "name is required")
		return
	}
	if err := models.ValidateNetworkCIDRs(req.CIDRs); err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	network := &models.Network{
		ID:        uuid.New().String(),
		Name:      req.Name,
		CIDRs:     req.CIDRs,
		CreatedAt: time.Now(),
	}

	if err := s.store.CreateNetwork(r.Context(), network); err != nil {
		s.logger.Error("create network", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to create network")
		return
	}

	writeJSON(w, http.StatusCreated, network)
}

func (s *Server) handleListNetworks(w http.ResponseWriter, r *http.Request) {
	networks, err := s.store.ListNetworks(r.Context())
	if err != nil {
		s.logger.Error("list networks", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to list networks")
		return
	}
	if !actorIsAdmin(r.Context()) {
		actor := ActorOf(r.Context())
		if actor == nil {
			writeJSON(w, http.StatusOK, []*models.Network{})
			return
		}
		cas, err := s.store.ListCAsByOwner(r.Context(), actor.ID)
		if err != nil {
			s.logger.Error("list cas by owner", "error", err)
			writeError(w, http.StatusInternalServerError, "failed to scope networks")
			return
		}
		owned := make(map[string]struct{}, len(cas))
		for _, ca := range cas {
			owned[ca.ID] = struct{}{}
		}
		filtered := networks[:0]
		for _, n := range networks {
			if _, ok := owned[n.CAID]; ok {
				filtered = append(filtered, n)
			}
		}
		networks = filtered
	}
	writeJSON(w, http.StatusOK, networks)
}

func (s *Server) handleGetNetwork(w http.ResponseWriter, r *http.Request) {
	id := chi.URLParam(r, "id")
	network, err := s.store.GetNetwork(r.Context(), id)
	if errors.Is(err, store.ErrNotFound) {
		writeError(w, http.StatusNotFound, "network not found")
		return
	}
	if err != nil {
		s.logger.Error("get network", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to get network")
		return
	}
	ok, err := s.canAccessNetwork(r.Context(), network)
	if err != nil {
		s.logger.Error("authz check", "error", err)
		writeError(w, http.StatusInternalServerError, "authz check failed")
		return
	}
	if !ok {
		writeError(w, http.StatusForbidden, "forbidden")
		return
	}

	writeJSON(w, http.StatusOK, network)
}

package api

import (
	"encoding/json"
	"net/http"
)

// settingEnforceTOTP duplicates the web package's exported key name so
// the API handler doesn't pull web in. Keep these literally identical
// — the value is the contract.
const settingEnforceTOTP = "enforce_2fa"

type settingsRequest struct {
	EnforceTOTP *bool `json:"enforce_2fa,omitempty"`
}

type settingsResponse struct {
	EnforceTOTP bool `json:"enforce_2fa"`
}

// handleGetSettings returns the current admin-tunable server settings.
// Admin-only because exposing the surface to non-admins gives them a
// view of the deployment's security posture.
func (s *Server) handleGetSettings(w http.ResponseWriter, r *http.Request) {
	if !actorIsAdmin(r.Context()) {
		writeError(w, http.StatusForbidden, "admin role required")
		return
	}
	v, _ := s.store.GetServerSetting(r.Context(), settingEnforceTOTP)
	writeJSON(w, http.StatusOK, settingsResponse{EnforceTOTP: v == "true"})
}

// handlePatchSettings updates one or more admin-tunable settings.
// Currently exposes only enforce_2fa; will grow with the rest of #47.
func (s *Server) handlePatchSettings(w http.ResponseWriter, r *http.Request) {
	if !actorIsAdmin(r.Context()) {
		writeError(w, http.StatusForbidden, "admin role required")
		return
	}
	var req settingsRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}
	if req.EnforceTOTP != nil {
		val := "false"
		if *req.EnforceTOTP {
			val = "true"
		}
		if err := s.store.SetServerSetting(r.Context(), settingEnforceTOTP, val); err != nil {
			s.logger.Error("set enforce_2fa", "error", err)
			writeError(w, http.StatusInternalServerError, "failed to update setting")
			return
		}
		s.recordAuditAction(r.Context(), auditSettingsEnforce2FA, settingEnforceTOTP, val)
	}
	v, _ := s.store.GetServerSetting(r.Context(), settingEnforceTOTP)
	writeJSON(w, http.StatusOK, settingsResponse{EnforceTOTP: v == "true"})
}

package api

import (
	"net/http"
	"strconv"

	"github.com/juev/nebula-mesh/internal/store"
)

const defaultAuditLimit = 100

func (s *Server) handleGetAuditLog(w http.ResponseWriter, r *http.Request) {
	if !actorIsAdmin(r.Context()) {
		writeError(w, http.StatusForbidden, "audit log access requires the admin role")
		return
	}
	filter := store.AuditFilter{
		Action: r.URL.Query().Get("action"),
		Limit:  defaultAuditLimit,
	}
	if l := r.URL.Query().Get("limit"); l != "" {
		n, err := strconv.Atoi(l)
		if err != nil {
			writeError(w, http.StatusBadRequest, "invalid limit: must be a number")
			return
		}
		if n < 1 {
			writeError(w, http.StatusBadRequest, "invalid limit: must be positive")
			return
		}
		if n > 1000 {
			n = 1000
		}
		filter.Limit = n
	}

	entries, err := s.store.ListAuditEntries(r.Context(), filter)
	if err != nil {
		s.logger.Error("list audit entries", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to get audit log")
		return
	}
	writeJSON(w, http.StatusOK, entries)
}

